func mergePaymentTaxTotals(pmt *bill.Payment) *tax.Total {
	var tt *tax.Total
	for _, pl := range pmt.Lines {
		if pl.Tax == nil {
			continue
		}
		if tt == nil {
			tt = pl.Tax
		} else {
			tt = tt.Merge(pl.Tax)
		}
	}
	return tt
}

